import tcb from '../src/index'
import assert from 'assert'
import { ERROR } from '../lib/const/code'
import config from './config.local'

describe('tcb.init: 初始化tcb', () => {
    it.skip('mock 导入本地config报错', async () => {
        jest.resetModules()
        jest.mock('./config', () => {
            throw Error('mock config require err')
        })
        try {
            const config = require('./config.local')
        } catch (e) {
            // console.log(e)
            assert(e.message)
        }
    })

    it('初始化tcb 不传secretId或secretKey', async () => {
        try {
            const app1 = tcb.init({ secretId: 'secretId' })
            const result1 = await app1.callFunction({
                name: 'test',
                data: { a: 1 }
            })

            // console.log(result)
        } catch (err) {
            assert(err.code === ERROR.INVALID_PARAM.code)
        }

        try {
            const app2 = tcb.init({ secretKey: 'secretKey' })
            const result2 = await app2.callFunction({
                name: 'test',
                data: { a: 1 }
            })
            // console.log(result)
        } catch (err) {
            assert(err.code === ERROR.INVALID_PARAM.code)
        }

        try {
            const app3 = tcb.init()
            const result3 = await app3.callFunction({
                name: 'test',
                data: { a: 1 }
            })
        } catch (err) {
            assert(err.code === ERROR.INVALID_PARAM.code)
        }

        // const result = await app.callFunction({
        //   name: 'test',
        //   data: { a: 1 }
        // })
        // console.log(result)
        // // assert(result.result, "执行云函数失败");
        // expect.objectContaining({ result: expect.anything() })
    }, 30000)

    it('mock parseContext', async () => {
        const mockContext = {
            memory_limit_in_mb: 256,

            time_limit_in_ms: 3000,

            request_id: '3169444b-25f4-11ea-81e5-525400235f2a',

            environ:
                'WX_CLIENTIP=10.12.23.71;WX_CLIENTIPV6=::ffff:10.12.23.71;WX_APPID=wx_test_appid;WX_OPENID=test_openid;WX_API_TOKEN=test_api_token;WX_CONTEXT_KEYS=WX_CLIENTIP,WX_CLIENTIPV6,WX_APPID,WX_OPENID,WX_API_TOKEN;TCB_ENV=luke-87pns;TCB_SEQID=1577153917182_0.13161529658114857_33555268;TRIGGER_SRC=tcb;TCB_SESSIONTOKEN=test_tcb_session_token;TCB_SOURCE=wx_devtools;TCB_CONTEXT_KEYS=TCB_ENV,TCB_SEQID,TRIGGER_SRC,TCB_SESSIONTOKEN,TCB_SOURCE;TENCENTCLOUD_SECRETID=TEST_SECRET_ID;TENCENTCLOUD_SECRETKEY=TEST_SECRET_KEY;TENCENTCLOUD_SESSIONTOKEN=TEST_SESSION_TOKEN;SCF_NAMESPACE=luke-87pns',

            function_version: '$LATEST',

            function_name: 'login',

            namespace: config.env
        }
        const contextObj = tcb.parseContext(mockContext)

        // 验证environ有value含;情形  如a=b;;sfsdf 解析结果为a=b 忽略分号后字符串
        const mockContext1 = {
            memory_limit_in_mb: 256,

            time_limit_in_ms: 3000,

            request_id: '3169444b-25f4-11ea-81e5-525400235f2a',

            environ:
                'a=b;;sfsdf;WX_CLIENTIP=10.12.23.71;WX_CLIENTIPV6=::ffff:10.12.23.71;WX_APPID=wx_test_appid;WX_OPENID=test_openid;WX_API_TOKEN=test_api_token;WX_CONTEXT_KEYS=WX_CLIENTIP,WX_CLIENTIPV6,WX_APPID,WX_OPENID,WX_API_TOKEN;TCB_ENV=luke-87pns;TCB_SEQID=1577153917182_0.13161529658114857_33555268;TRIGGER_SRC=tcb;TCB_SESSIONTOKEN=test_tcb_session_token;TCB_SOURCE=wx_devtools;TCB_CONTEXT_KEYS=TCB_ENV,TCB_SEQID,TRIGGER_SRC,TCB_SESSIONTOKEN,TCB_SOURCE;TENCENTCLOUD_SECRETID=TEST_SECRET_ID;TENCENTCLOUD_SECRETKEY=TEST_SECRET_KEY;TENCENTCLOUD_SESSIONTOKEN=TEST_SESSION_TOKEN;SCF_NAMESPACE=luke-87pns',

            function_version: '$LATEST',

            function_name: 'login',

            namespace: config.env
        }
        const contextObj1 = tcb.parseContext(mockContext1)
        assert(contextObj1.environ.a === 'b')

        // 验证含environment字段，且json字符串为含特殊字符情形
        const mockContext2 = {
            memory_limit_in_mb: 256,

            time_limit_in_ms: 3000,

            request_id: '3169444b-25f4-11ea-81e5-525400235f2a',

            environ:
                'a=b;;sfsdf;WX_CLIENTIP=10.12.23.71;WX_CLIENTIPV6=::ffff:10.12.23.71;WX_APPID=wx_test_appid;WX_OPENID=test_openid;WX_API_TOKEN=test_api_token;WX_CONTEXT_KEYS=WX_CLIENTIP,WX_CLIENTIPV6,WX_APPID,WX_OPENID,WX_API_TOKEN;TCB_ENV=luke-87pns;TCB_SEQID=1577153917182_0.13161529658114857_33555268;TRIGGER_SRC=tcb;TCB_SESSIONTOKEN=test_tcb_session_token;TCB_SOURCE=wx_devtools;TCB_CONTEXT_KEYS=TCB_ENV,TCB_SEQID,TRIGGER_SRC,TCB_SESSIONTOKEN,TCB_SOURCE;TENCENTCLOUD_SECRETID=TEST_SECRET_ID;TENCENTCLOUD_SECRETKEY=TEST_SECRET_KEY;TENCENTCLOUD_SESSIONTOKEN=TEST_SESSION_TOKEN;SCF_NAMESPACE=luke-87pns',

            function_version: '$LATEST',

            function_name: 'login',

            namespace: config.env,
            environment: JSON.stringify({ a: 'b;c;fs;d' })
        }

        const contextObj2 = tcb.parseContext(mockContext2)
        assert(contextObj2.environment.a === 'b;c;fs;d')

        // 验证getCloudbaseContext
        const cloudbaseContext = tcb.getCloudbaseContext(mockContext)
        assert(cloudbaseContext.WX_CLIENTIP === '10.12.23.71')

        // 验证parseContext 参数错误
        expect(() => {
            tcb.parseContext('wrong context')
        }).toThrow(new Error('context 必须为对象类型'))

        // 验证envrionment 解析报错
        const mockContext3 = {
            environment: {}
        }

        expect(() => {
            tcb.parseContext(mockContext3)
        }).toThrow(new Error('无效的context对象，请使用 云函数入口的context参数'))
    })

    it('测试 getAuthContext', async () => {
        const app = tcb.init(config)
        const mockContext = {
            environment: JSON.stringify({
                TCB_UUID: 'uuid',
                LOGINTYPE: 'QQ-MINI',
                QQ_OPENID: 'QQ_OPENID',
                QQ_APPID: 'QQ_APPID'
            })
        }

        const authContextRes = await app.auth().getAuthContext(mockContext)
        assert.deepStrictEqual(authContextRes, {
            uid: 'uuid',
            loginType: 'QQ-MINI',
            appId: 'QQ_APPID',
            openId: 'QQ_OPENID'
        })
    })
})
